1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface QuoteItem {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: QuoteItem[];
15	}
16	
17	export type Step = QuoteStep;
18	
19	export interface Scenario {
20	  customer: Customer;
21	  steps: Step[];
22	}
23	
24	export interface QuoteResult {
25	  premium: number;
26	}
27	
28	export type StepResult = QuoteResult;
29	
30	export interface ScenarioResult {
31	  results: StepResult[];
32	}
33	
34	const basePremiums: Record<string, number> = {
35	  sword: 100,
36	  amulet: 60,
37	  staff: 80,
38	  potion: 40,
39	  rune: 25,
40	  moonstone: 25,
41	};
42	
43	const PROCESSING_FEE = 5;
44	
45	const BLOCK_SIZE = 3;
46	
47	const BLOCK_OF_THREE_BASE = 60;
48	
49	const componentTypes = new Set(["rune", "moonstone"]);
50	
51	const countByType = (items: QuoteItem[]): Record<string, number> =>
52	  items.reduce<Record<string, number>>((counts, item) => {
53	    counts[item.type] = (counts[item.type] ?? 0) + 1;
54	    return counts;
55	  }, {});
56	
57	const basePremiumForGroup = (type: string, count: number): number => {
58	  if (componentTypes.has(type) && count === BLOCK_SIZE) {
59	    return BLOCK_OF_THREE_BASE;
60	  }
61	  return basePremiums[type] * count;
62	};
63	
64	const CURSE_SURCHARGE_RATE = 0.5;
65	
66	const FIRST_INSURANCE_RATE = 0.1;
67	
68	const HIGH_ENCHANTMENT_THRESHOLD = 5;
69	
70	const HIGH_ENCHANTMENT_RATE = 0.3;
71	
72	const itemBasePremium = (item: QuoteItem): number => basePremiums[item.type];
73	
74	const isCursed = (item: QuoteItem): boolean => item.cursed === true;
75	
76	const curseSurcharge = (item: QuoteItem): number =>
77	  isCursed(item) ? itemBasePremium(item) * CURSE_SURCHARGE_RATE : 0;
78	
79	const enchantmentLevel = (item: QuoteItem): number => item.enchantment ?? 0;
80	
81	const highEnchantmentSurcharge = (item: QuoteItem): number =>
82	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD
83	    ? itemBasePremium(item) * HIGH_ENCHANTMENT_RATE
84	    : 0;
85	
86	const firstInsuranceSurcharge = (item: QuoteItem): number =>
87	  itemBasePremium(item) * FIRST_INSURANCE_RATE;
88	
89	const itemSurcharges = (item: QuoteItem): number =>
90	  curseSurcharge(item) +
91	  highEnchantmentSurcharge(item) +
92	  firstInsuranceSurcharge(item);
93	
94	const sumOfBasePremiums = (items: QuoteItem[]): number => {
95	  const counts = countByType(items);
96	  return Object.entries(counts).reduce(
97	    (sum, [type, count]) => sum + basePremiumForGroup(type, count),
98	    0
99	  );
100	};
101	
102	const sumOfItemSurcharges = (items: QuoteItem[]): number =>
103	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
104	
105	const LOYALTY_YEARS_THRESHOLD = 2;
106	
107	const LOYALTY_DISCOUNT_RATE = 0.2;
108	
109	const loyaltyDiscount = (customer: Customer, basePremium: number): number =>
110	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
111	    ? basePremium * LOYALTY_DISCOUNT_RATE
112	    : 0;
113	
114	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
115	
116	const followUpDiscount = (basePremium: number, isFollowUp: boolean): number =>
117	  isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
118	
119	const quotePremium = (
120	  items: QuoteItem[],
121	  customer: Customer,
122	  isFollowUp: boolean
123	): number => {
124	  const basePremium = sumOfBasePremiums(items);
125	  const surcharges = sumOfItemSurcharges(items);
126	  const discount =
127	    loyaltyDiscount(customer, basePremium) +
128	    followUpDiscount(basePremium, isFollowUp);
129	  return Math.ceil(basePremium + surcharges - discount + PROCESSING_FEE);
130	};
131	
132	const priorQuoteCount = (steps: Step[], index: number): number =>
133	  steps.slice(0, index).filter((step) => step.op === "quote").length;
134	
135	export function runScenario(scenario: Scenario): ScenarioResult {
136	  const results = scenario.steps.map((step, index) => {
137	    const isFollowUp = priorQuoteCount(scenario.steps, index) > 0;
138	    return {
139	      premium: quotePremium(step.items, scenario.customer, isFollowUp),
140	    };
141	  });
142	  return { results };
143	}
